package java_sample_project;

public class Switchopp {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a=5,b=6;
		int result;
		char opr='+';
		switch(opr) {
		case '+':result=a+b;
		System.out.println("result="+result);
		break;
		case '-':result=a-b;
		System.out.println("result="+result);
		break;
		case '*':result=a*b;
		System.out.println("result="+result);
		break;
		case '/':result=a/b;
		System.out.println("result="+result);
	break;
		}

	}

}
